INSERT INTO `articles` (`id`, `author_id`, `category_id`, `title`, `slug`, `body`, `status`, `published_at`, `submitted_at`, `views_count`, `draft_origin`, `restore_to_status`, `restore_published_at`, `archived_by_admin_id`, `archived_at`, `deleted_at`, `created_at`, `updated_at`, `cover_image`) VALUES
(11, 1, 8, 'مقتل عناصر متعاونة مع الاحتلال في كمين للمقاومة شرقي خانيونس', 'مقتل-عناصر-متعاونة-مع-الاحتلال-في-كمين-للمقاومة-شرقي-خانيونس', 'قُتل، اليوم الإثنين، عدد من عناصر العصابات المتعاونة مع الاحتلال الإسرائيلي، شرق مدينة خانيونس، جنوب قطاع غزة، بعد وقوعهم في كمين للمقاومة الفلسطينية.\r\n\r\n\r\nوأفادت وسائل إعلام محلية، نقلاً عن شهود عيان، أن المقاومة الفلسطينية أوقعت عدداً من عناصر تلك العصابات في كمين، تلاه إطلاق نار كثيف في المنطقة الشرقية من مدينة خانيونس.\r\n\r\nوأضافت أن جيبًا عسكرياً كان يقل عدداً من عناصر تلك المجموعات تعرّض للاستهداف بقذيفة \"تاندوم\" من قبل عناصر المقاومة الفلسطينية، ما أدى إلى تدمير جيبين ومقتل من بداخلهما.\r\n\r\nوأشارت إلى أن طائرات الاحتلال عادت لاحقًا لقصف الآليات المستهدفة، بعد فشلها في توفير غطاء جوي وتأمين الحماية للمجموعة.', 'published', '2026-04-20 13:08:11', '2026-04-20 13:07:58', 102, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-20 13:03:42', '2026-04-28 08:29:31', 'articles/covers/s1fdf4-1770729081.webp'),
(12, 1, 7, 'سلطة النقد تحدد آلية خصم أقساط القروض لموظفي القطاع العام', 'سلطة-النقد-تحدد-آلية-خصم-أقساط-القروض-لموظفي-القطاع-العام', 'أصدرت سلطة النقد الفلسطينية، اليوم الاثنين، التعميم رقم (43/2026) الموجّه إلى جميع المصارف العاملة في فلسطين، لتنظيم آلية خصم أقساط القروض، بالتزامن مع قرار وزارة المالية الفلسطينية صرف دفعة من رواتب شهر كانون الثاني 2026 بقيمة 2,000 شيكل.\r\n\r\nوأوضح التعميم أنه سيتم اقتطاع قيمة القسط كاملة للموظفين الذين يتقاضون راتباً كاملاً أو ما نسبته 95% فأكثر، مع الالتزام بالسقف القانوني المحدد للخصم، فيما تقتصر نسبة الخصم لبقية الموظفين على 10% فقط من قيمة الدفعة المحوّلة.\r\n\r\nوبحسب بيان سلطة النقد، فإن هذا الإجراء يهدف إلى ضمان استمرارية سداد الالتزامات المالية، مع مراعاة الأوضاع المعيشية لموظفي القطاع العام، والحفاظ على حد أدنى من السيولة النقدية لديهم.', 'published', '2026-04-20 13:08:09', '2026-04-20 13:07:57', 99, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-20 13:04:54', '2026-04-28 08:29:33', 'articles/covers/d26682a6-8cde-49ed-8d12-772b14c7aa3a.webp'),
(26, 6, 8, 'قصف مستشفى المعمداني يحوّل ملاذ المرضى إلى مشهد فاجعة', 'al-ahli-hospital-attack-gaza', 'أقدمت طائرات المحتَل الإسرائيلي بعد السابعة مساءً بالتوقيت المحلّي (جرينتش +03) على الإغارة وبشكل عنيف جدًا على حي الزيتون و‌الشجاعية، ثم عاودت الطائرات الحربية غارة قوية جدًا لكنها استهدفت هذه المرة ساحة مستشفى المعمداني الأهلي، والذي كان قد استقبلَ طوال الأيام الماضيّة مئات النازحين المدنيين عدى عن مئات آخرين من المرضى والجرحى وغيرهم. كانت الضربة الجوية الإسرائيليّة قوية جدًا وأظهر مقطع فيديو انتشرَ على وسائل التواصل الاجتماعي وبثته قنوات عربية ودوليّة حجم الغارة التي طالت المشفى وما أعقبها من انفجار ضخم هزّ كامل المناطق المحيطة بموقع الضربة فضلًا عن ألسنة اللهب التي لم تهدأ. كان من الواضح أنّ الضربة قوية جدًا وأنها استهدفت وبشكل متعمّد مستشفى المعمداني وسط مدينة غزة المعروفة إحداثياته أساسًا لدى قوات الاحتلال الإسرائيلي.\r\n\r\nسارعت سيارات الإسعاف لموقع المذبحة التي ارتكبتها إسرائيل وحاولت التعامل مع الضحايا على قيدِ الحياة تاركةً الجثث ملقاة في جميعِ الأماكن لعدم قدرة الإسعاف الفلسطيني على التعامل مع كلّ هذا العدد من ضحايا الإرهاب الصهيوني. أشارت التقديرات الأولية إلى مقتل ما بين 200 إلى 300 مدنيٍّ فلسطيني في القصف الإسرائيلي الذي تعمَّد استهداف مستشفى المعمداني الممتلئ عن آخره بالمدنيين النازحين وبضحايا الغارات الإسرائيليّة. تصاعدَ عدد الضحايا بشكل كبير بسبب الموقع المستهدَف وعدد المدنيين ممن كانوا داخله، حيث أعلنت وزارة الصحة في غزة في مؤتمر صحفي في المستشفى من بين جثامين الشهداء عن «استشهاد أكثر من 500 فلسطيني في قصفِ الاحتلال لمستشفى الأهلي المعمداني»، وما عقّد الأمور أكثر هو انقطاع الكهرباء بشكل كامل عن مستشفى الشفاء بسببِ الحصار الإسرائيلي وهو المشفى الذي وصل له العشرات من ضحايا المجزرة الإسرائيليّة.\r\n\r\nخرجَ المدير العام لوزارة الصحة في قطاع غزة في تصريحاتٍ صحفيّة شرحَ فيها بعضًا من تفاصيل هذه المجزرة الإسرائيليّة، حيث أكّد بدايةً أنّ المستشفى المعمداني لم يُستهدف مطلقًا وبشكل مباشر في الحروب السابقة مضيفًا أنّ هذا المشفى كان يُعتبر ملاذًا آمنًا لسكان القطاع. شرحَ المدير العام كيف أنّ فرق الإنقاذ وجدت صعوبة في التعرف على جثث الضحايا مؤكّدًا أن كل الضحايا حرفيًا من المدنيين، لافتًا إلى أن إحداثيات المستشفيات تُسلم للجنة الدولية للصليب الأحمر التي تُسلّمها بدورها للاحتلال الإسرائيلي تفاديًا لارتكابِ مجازر في حقّ المستشفيات ومن فيها. أقامَ وكيل وزارة الصحة في غزة مؤتمرًا صحافيًا هو الآخر وفيه أعلن وبصريح العبارة أنّ الاحتلال كان قد هدَّد إدارة مستشفى المعمداني لإخلائه قبل المجزرة الوحشيّة.', 'published', '2026-04-28 07:59:40', '2026-04-28 07:59:34', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 07:59:29', '2026-04-28 07:59:40', 'articles/covers/قصف مستشفى المعمداني.webp'),
(27, 6, 8, 'مخيم جباليا تحت الركام بعد غارات عنيفة على شمال غزة', 'jabalia-camp-under-rubble', 'في مخيم جباليا شمال قطاع غزة، حيث تتداخل البيوت الضيقة والأزقة المكتظة وحياة اللاجئين الممتدة منذ عقود، جاءت الغارات لتضيف فصلًا جديدًا من الفاجعة. لم يكن المخيم مجرد مساحة سكنية، بل مكانًا تعيش فيه عائلات كثيرة فوق بعضها تقريبًا، وسط ظروف إنسانية صعبة وحصار طويل وحرب لا تترك مكانًا بعيدًا عن الخطر.\r\n\r\nمع اشتداد القصف، انهارت مبانٍ كاملة فوق ساكنيها، وتحولت أحياء من المخيم إلى ركام وغبار. كان الناس يركضون بين الحجارة بحثًا عن أبنائهم وجيرانهم، بينما ارتفعت أصوات الاستغاثة من تحت الأنقاض. في غزة، لا تكون لحظة القصف نهاية المشهد، بل بدايته؛ بعدها تبدأ رحلة البحث الطويلة عن الناجين والشهداء.\r\n\r\nفرق الإنقاذ عملت في ظروف شبه مستحيلة، بإمكانيات محدودة ومعدات لا تكفي لحجم الدمار. كثيرون استخدموا أيديهم لرفع الحجارة، وآخرون وقفوا عاجزين أمام بيوت اختفت ملامحها. كل دقيقة كانت تعني احتمال إنقاذ حياة، وكل تأخير كان يزيد الألم.\r\n\r\nجباليا في ذلك اليوم لم تكن مجرد خبر عاجل، بل صورة مكثفة عن معنى استهداف منطقة مكتظة بالسكان. فحين يُقصف مخيم بهذا الحجم وبهذا الاكتظاظ، يصبح المدنيون هم الضحية الأولى، وتصبح كل عائلة معرضة لأن تفقد أكثر من فرد في لحظة واحدة.\r\n\r\nهذا الحدث ترك أثرًا عميقًا في ذاكرة الحرب، لأنه أظهر كيف تتحول المخيمات، وهي أصلًا رمز للجوء والمعاناة، إلى ساحات جديدة للدمار والنزوح داخل النزوح نفسه.', 'published', '2026-04-28 08:31:14', '2026-04-28 08:30:52', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:04:32', '2026-04-28 08:31:14', 'articles/covers/مخيم جباليا.jpg'),
(28, 8, 7, 'الهدنة الإنسانية الأولى في غزة: توقف مؤقت للحرب لا نهاية للأزمة', 'first-humanitarian-pause-gaza', 'بعد أسابيع طويلة من القصف والحصار والنزوح، دخلت الهدنة الإنسانية الأولى في غزة حيّز التنفيذ، لتفتح نافذة قصيرة وسط حرب أنهكت المدنيين ودفعت القطاع إلى حافة الانهيار. لم تكن الهدنة نهاية للحرب، لكنها كانت أول لحظة يتراجع فيها صوت القصف قليلًا، ويبحث الناس فيها عن فرصة لالتقاط الأنفاس.\r\n\r\nبالنسبة لسكان غزة، لم تكن الهدنة حدثًا سياسيًا فقط. كانت وقتًا قصيرًا لتفقد البيوت المدمرة، والبحث عن المفقودين، والوقوف في طوابير طويلة للحصول على الطعام والماء والدواء. كثيرون خرجوا من أماكن النزوح بحذر، لا يعرفون هل سيجدون بيوتهم قائمة أم تحولت إلى ركام.\r\n\r\nالهدنة حملت أيضًا ملف الأسرى والمحتجزين إلى الواجهة، وربطت بين المسار الإنساني والمسار التفاوضي. فكل ساعة هدوء كانت مرتبطة بتفاهمات دقيقة، وبوساطات إقليمية ودولية، وبحسابات سياسية لا تنفصل عن الميدان.\r\n\r\nلكن الهدنة كشفت كذلك هشاشة الوضع. فالناس في غزة لم يشعروا بأن الخطر انتهى، بل بأنهم يعيشون استراحة مؤقتة من حرب قد تعود في أي لحظة. لذلك اختلط الارتياح بالخوف، والأمل بالحذر، وانتظار المساعدات بقلق العودة إلى القصف.\r\n\r\nسياسيًا، أظهرت الهدنة أن الضغط الإنساني يمكن أن يفتح مسارًا للتفاوض، لكنه لا يكفي وحده لإنهاء الكارثة. أما إنسانيًا، فقد كانت دليلًا على حجم ما يحتاجه الناس حين يتوقف القصف قليلًا: طعام، ماء، دواء، مأوى، ووقت لدفن الشهداء.', 'published', '2026-04-28 08:31:10', '2026-04-28 08:30:35', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:08:25', '2026-04-28 08:31:10', 'articles/covers/الهدنة الأولى.webp'),
(29, 8, 7, 'تمديد الهدنة في غزة ليومين إضافيين وسط ترقب إنساني وسياسي', 'gaza-humanitarian-pause-extended-two-days', 'جاء الإعلان عن تمديد الهدنة الإنسانية في غزة ليومين إضافيين كخبر انتظره الناس بقلق أكثر من الفرح. فكل يوم إضافي من الهدوء كان يعني فرصة جديدة للبحث عن المفقودين، وإدخال بعض المساعدات، وتخفيف الضغط عن المستشفيات والعائلات النازحة.\r\n\r\nلكن هذا التمديد لم يكن كافيًا لإنهاء المعاناة. فغزة التي عاشت أسابيع من القصف لم تكن بحاجة إلى يومين فقط، بل إلى وقف شامل يفتح الطريق أمام علاج الجرحى، وعودة النازحين، ودخول الطعام والدواء والوقود بكميات حقيقية. لذلك بقي التمديد خطوة محدودة داخل أزمة أكبر بكثير.\r\n\r\nمن الناحية السياسية، عكس التمديد استمرار دور الوساطات، وخصوصًا في ملفات الأسرى والمحتجزين والمساعدات. كما كشف أن أطراف الحرب باتت تتحرك تحت ضغط إنساني وإقليمي ودولي، حتى لو بقيت الحسابات العسكرية حاضرة بقوة.\r\n\r\nفي الشارع الغزي، كان الناس يتعاملون مع الهدنة بحذر. كثيرون لم يتركوا أماكن النزوح لأنهم لا يثقون بطول الهدوء، وآخرون خرجوا فقط للبحث عن احتياجاتهم الأساسية. الخوف من انتهاء الهدنة كان حاضرًا في كل حديث، لأن التجربة علمت الناس أن القصف قد يعود فجأة.\r\n\r\nلقد منح التمديد المدنيين وقتًا إضافيًا، لكنه لم يمنحهم الأمان الكامل. وبقي السؤال معلقًا: هل تكون الهدنة بداية طريق نحو وقف الحرب، أم مجرد استراحة قصيرة قبل جولة جديدة من الألم؟', 'published', '2026-04-28 08:31:16', '2026-04-28 08:30:34', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:09:40', '2026-04-28 08:31:16', 'articles/covers/شاحنات المساعدات.webp'),
(30, 8, 7, 'محكمة العدل الدولية تضع حرب غزة أمام اختبار القانون الدولي', 'icj-provisional-measures-gaza', 'مع صدور أمر محكمة العدل الدولية بشأن التدابير المؤقتة في القضية المتعلقة بغزة، دخلت الحرب مرحلة جديدة خارج حدود الميدان العسكري. لم تعد المشاهد القادمة من القطاع مجرد صور للدمار والنزوح، بل أصبحت جزءًا من ملف قانوني دولي يناقش مسؤوليات الدول وحدود القوة وحماية المدنيين.\r\n\r\nالقرار لم يوقف الحرب مباشرة، لكنه حمل أهمية سياسية وقانونية كبيرة. فقد وضع ما يجري في غزة أمام أعلى هيئة قضائية دولية، وأعاد إلى الواجهة أسئلة الإبادة، والعقاب الجماعي، وواجبات الاحتلال، ومدى التزام المجتمع الدولي بحماية السكان المدنيين.\r\n\r\nبالنسبة للفلسطينيين، كان المسار القانوني محاولة لنقل الألم من الشاشات إلى قاعات العدالة. فالضحايا في غزة لا يحتاجون فقط إلى توثيق قصصهم، بل إلى مساءلة حقيقية تمنع تكرار الجرائم وتحاسب المسؤولين عنها.\r\n\r\nعلى المستوى السياسي، أظهر القرار أن الحرب لم تعد تُقاس فقط بنتائج المعارك، بل أيضًا بتداعياتها القانونية والدبلوماسية. كما وضع إسرائيل وحلفاءها أمام ضغط دولي متزايد، حتى لو بقي تنفيذ القرارات مرتبطًا بموازين القوة والإرادة السياسية.\r\n\r\nهذه المحطة لا تمحو دماء الضحايا ولا تعيد البيوت المهدمة، لكنها تؤكد أن الذاكرة القانونية للحرب بدأت تتشكل، وأن غزة لم تعد فقط ساحة حرب، بل قضية اختبار للعالم كله: هل يمكن للقانون الدولي أن يحمي المدنيين حين يكونون تحت القصف؟', 'published', '2026-04-28 08:31:12', '2026-04-28 08:30:31', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:11:03', '2026-04-28 08:31:12', 'articles/covers/محكمة العدل الدولية.jpg'),
(31, 9, 8, 'مجزرة الطحين: حين صار البحث عن الخبز طريقًا إلى الموت', 'flour-massacre-gaza-hunger-aid', 'في شمال غزة، لم يعد الجوع مجرد شعور عابر، بل صار واقعًا يوميًا يطارد العائلات في كل ساعة. خرج الناس بحثًا عن الطحين، لا عن رفاهية ولا عن خيار إضافي، بل عن كيس يمكن أن يؤجل جوع الأطفال يومًا آخر. كان المشهد في بدايته طابورًا طويلًا من مدنيين أنهكهم الحصار، لكنه انتهى بفاجعة جديدة.\r\n\r\nتجمّع مئات الفلسطينيين على أمل الوصول إلى المساعدات، وسط نقص شديد في الغذاء وانقطاع الإمدادات عن مناطق واسعة. كثيرون جاءوا بعد أيام من الجوع، وبعضهم كان يحمل في ذهنه صورة أطفاله بانتظار رغيف خبز. لكن لحظة الانتظار تحولت إلى موت، وسقط عشرات المدنيين بين شهيد وجريح.\r\n\r\nمجزرة الطحين كانت من أكثر أحداث الحرب تعبيرًا عن قسوة الحصار. فهي لم تقع في جبهة قتال، بل في مكان ينتظر فيه الناس الطعام. وهذا ما جعلها صادمة؛ أن يصبح الطريق إلى كيس طحين محفوفًا بالموت، وأن يتحول الجوع نفسه إلى سلاح يضغط على المدنيين.\r\n\r\nفي غزة، لا تنفصل المساعدات عن الكرامة. فالناس الذين كانوا يعملون ويطعمون عائلاتهم وجدوا أنفسهم فجأة في طوابير طويلة، يلاحقون شاحنات قليلة لا تكفي مدينة محاصرة. ثم جاءت المجزرة لتقول إن حتى انتظار الطعام لم يعد آمنًا.\r\n\r\nهذا الحدث بقي شاهدًا على أن الحرب لا تقتل بالقصف وحده، بل بالجوع والحصار وحرمان الناس من أبسط أسباب الحياة. كان الطحين في ذلك اليوم أكثر من غذاء؛ كان رمزًا لحق الناس في البقاء.', 'published', '2026-04-28 08:31:07', '2026-04-28 08:30:14', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:13:20', '2026-04-28 08:31:07', 'articles/covers/مجزرة الطحين.jpg'),
(32, 9, 8, 'إغلاق معبر رفح يعمّق عزلة غزة ويخنق طريق المساعدات', 'rafah-crossing-closure-gaza-aid-crisis', 'مع إغلاق معبر رفح، شعر سكان غزة أن الباب الأخير إلى العالم بدأ يضيق أكثر. لم يكن المعبر مجرد نقطة عبور على الحدود، بل كان بالنسبة لكثيرين طريقًا للعلاج، وممرًا للمساعدات، ومنفذًا نادرًا للخروج من واقع الحرب والحصار.\r\n\r\nالإغلاق لم يكن تفصيلًا إداريًا أو خبرًا حدوديًا عابرًا. في غزة، كل معبر مغلق يعني نقصًا أكبر في الغذاء، وتأخرًا في الدواء، وانقطاعًا في الوقود، ومزيدًا من العائلات التي تنتظر المجهول. المرضى الذين كانوا يأملون بالخروج للعلاج وجدوا أنفسهم عالقين، والمساعدات التي كان الناس ينتظرونها أصبحت أكثر صعوبة في الوصول.\r\n\r\nالمستشفيات كانت أصلًا تعمل في ظروف شبه منهارة، ومع إغلاق المعبر ازداد الضغط عليها. نقص الوقود يعني توقف مولدات، ونقص الدواء يعني ألمًا أطول للجرحى، ونقص المعدات يعني أن الأطباء يواجهون الموت بأيدٍ شبه فارغة.\r\n\r\nأما النازحون، فقد عاشوا الإغلاق كفصل جديد من العزلة. فالخيام المكتظة، وندرة المياه، وغلاء الطعام، كلها أصبحت أثقل حين أُغلق الطريق الذي كان يمكن أن يحمل بعض الإغاثة. صار المعبر رمزًا لحياة كاملة معلقة على بوابة لا تُفتح.\r\n\r\nإغلاق رفح أظهر أن الحرب على غزة لا تُدار بالقصف فقط، بل بالسيطرة على الحركة والمساعدات والنجاة. وحين يُغلق المعبر، لا تُغلق بوابة حديدية فقط، بل يُغلق معها أمل مريض ونداء عائلة وحاجة مدينة كاملة إلى الحياة.', 'published', '2026-04-28 08:31:06', '2026-04-28 08:30:13', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:16:17', '2026-04-28 08:31:06', 'articles/covers/تعليق الشاحنات.webp'),
(33, 9, 8, 'نزوح غزة المتكرر: عائلات تحمل بيوتها على الذاكرة', 'repeated-displacement-gaza-families', 'في غزة، لم يعد النزوح حدثًا واحدًا يبدأ بالخروج من البيت وينتهي بالوصول إلى مكان جديد. صار النزوح رحلة متكررة، يتنقل فيها الناس من حي إلى مدرسة، ومن مدرسة إلى خيمة، ومن خيمة إلى مساحة أخرى لا يعرفون إن كانت أكثر أمانًا أو أقل خطرًا.\r\n\r\nتخرج العائلة غالبًا بما تستطيع حمله فقط: حقيبة صغيرة، بعض الملابس، أوراق مهمة، وربما صورة من زمن كان فيه البيت قائمًا. أما باقي الحياة فتُترك خلف الباب: الأثاث، الكتب، الألعاب، الذكريات، ورائحة المكان الذي كان اسمه بيتًا.\r\n\r\nكل موجة نزوح جديدة تعني تعبًا جديدًا. الأطفال يسألون إلى أين نذهب، والكبار لا يملكون جوابًا. الطريق مزدحم، الماء قليل، الطعام نادر، والخوف يرافق الناس من مكان إلى آخر. حتى الوصول لا يعني الراحة، لأن الخيمة نفسها قد تصبح محطة مؤقتة قبل نزوح آخر.\r\n\r\nالنزوح المتكرر لا يسرق المكان فقط، بل يسرق الإحساس بالاستقرار. فالإنسان حين لا يعرف أين سينام غدًا، ولا أين سيجد الماء، ولا هل سيبقى المكان الذي وصل إليه آمنًا، يعيش حربًا داخلية لا تقل قسوة عن القصف.\r\n\r\nهذه القصة ليست قصة عائلة واحدة، بل قصة معظم غزة. مدينة كاملة تقريبًا حملت بيوتها على الذاكرة، وسارت في طرق النزوح وهي تعرف أن العودة ليست قريبة، وأن المكان الذي خرجت منه قد لا يكون موجودًا حين تعود.', 'published', '2026-04-28 08:31:00', '2026-04-28 08:30:11', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:17:56', '2026-04-28 08:31:00', 'articles/covers/نزووح.jpg'),
(34, 8, 10, 'الرصيف الأمريكي لغزة: مساعدات بحرية وسط حصار بري خانق', 'us-pier-gaza-humanitarian-aid', 'أثار الإعلان عن إنشاء رصيف أمريكي مؤقت لإيصال المساعدات إلى غزة أسئلة كثيرة، ليس فقط حول الجانب الإنساني، بل حول السياسة التي تحيط بالمساعدات نفسها. ففي الوقت الذي كان فيه سكان القطاع يواجهون الجوع والحصار وانهيار الخدمات، ظهر المسار البحري كحل استثنائي، بينما بقي السؤال الأكبر: لماذا لا تُفتح المعابر البرية بشكل كامل وآمن؟\r\n\r\nمن الناحية الإنسانية، كل طريق يدخل الطعام والدواء إلى غزة مهم. لكن حجم الكارثة كان أكبر من أن يُعالج بممر مؤقت أو شحنات محدودة. فالناس في القطاع لا يحتاجون إلى حلول رمزية، بل إلى تدفق مستمر وواسع للمساعدات، وإلى رفع القيود التي جعلت الغذاء والوقود والدواء يصلون ببطء شديد.\r\n\r\nسياسيًا، بدا الرصيف وكأنه محاولة أمريكية لإظهار تحرك إنساني في لحظة تصاعدت فيها الانتقادات الدولية. لكنه في الوقت نفسه كشف التناقض القائم بين الحديث عن المساعدات واستمرار الحرب والحصار. فلا يمكن لأي مشروع إغاثي أن يكون بديلًا عن وقف القصف وفتح المعابر.\r\n\r\nفي غزة، لم يكن الناس يناقشون شكل الممر بقدر ما كانوا ينتظرون وصول الغذاء فعلًا. بالنسبة للأم التي لا تجد حليبًا لطفلها، والمريض الذي ينتظر دواء، والعائلة التي تعيش في خيمة، لا يهم إن جاءت المساعدة من البحر أو البر؛ المهم أن تصل بسرعة وبكرامة وبما يكفي.\r\n\r\nلذلك تحول الرصيف الأمريكي إلى عنوان سياسي وإنساني معقد: مساعدات مطلوبة، لكنها غير كافية، ومسار جديد لا يلغي حقيقة أن غزة كانت بحاجة إلى كسر الحصار لا إلى إدارة الجوع بطرق بديلة.', 'published', '2026-04-28 08:31:04', '2026-04-28 08:30:32', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:21:13', '2026-04-28 08:31:04', 'articles/covers/الرصيف الأمريكي.jpeg'),
(35, 8, 10, 'جبهة لبنان تدخل على خط الحرب وتغيّر حسابات الإقليم', 'lebanon-front-opens-gaza-war', 'منذ الأيام الأولى للحرب على غزة، بدأت جبهة لبنان تتحرك كعامل جديد في معادلة الصراع. إطلاق الصواريخ من جنوب لبنان والرد المدفعي الإسرائيلي فتحا مسارًا إضافيًا للتوتر، وجعلا الحرب تتجاوز حدود القطاع إلى مساحة إقليمية أوسع.\r\n\r\nأهمية هذه الجبهة أنها فرضت على إسرائيل حسابات متعددة. فلم يعد التركيز العسكري والسياسي محصورًا في غزة وحدها، بل أصبح الشمال حاضرًا في تقديرات التصعيد والردع واحتمالات توسع المواجهة. ومع كل تبادل للنار، كان القلق يكبر من أن تتحول الحرب إلى صراع أوسع.\r\n\r\nبالنسبة للمنطقة، بدت جبهة لبنان كرسالة سياسية وعسكرية في وقت واحد. فهي مرتبطة بغزة من جهة، وبميزان القوى الإقليمي من جهة أخرى. لذلك لم يكن ما يجري على الحدود مجرد اشتباك محدود، بل جزءًا من صورة أكبر عنوانها أن الحرب على غزة قادرة على إشعال جبهات أخرى.\r\n\r\nهذا التطور أعاد إلى الواجهة دور القوى الإقليمية، وحدود التدخل، ومخاطر الانزلاق إلى حرب أوسع. كما وضع المدنيين في جنوب لبنان وشمال فلسطين المحتلة أمام واقع جديد من النزوح والخوف والترقب.\r\n\r\nفتح جبهة لبنان كان من الأحداث التي غيّرت موازين الحرب، ليس لأنه أنهى معاناة غزة، بل لأنه نقل الضغط إلى مساحة أخرى، وأكد أن استمرار الحرب يفتح الباب أمام تحولات لا يمكن ضبطها بسهولة.', 'published', '2026-04-28 08:31:03', '2026-04-28 08:30:30', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:22:53', '2026-04-28 08:31:03', 'articles/covers/حدود لبنان.webp'),
(36, 6, 8, 'النصيرات تعيش أحد أكثر أيام الحرب دموية', 'nuseirat-operation-deadly-day-gaza', 'في الثامن من يونيو، عاش مخيم النصيرات وسط قطاع غزة يومًا من أكثر أيام الحرب دموية. بدأ المشهد بأصوات قصف كثيف، ثم تحولت الشوارع إلى فوضى من الدخان والركام وسيارات الإسعاف والناس الذين يحملون المصابين بأيديهم، بينما كان المدنيون يحاولون فهم ما يحدث وسط الخوف والصراخ.\r\n\r\nالنصيرات ليس مجرد اسم على الخريطة. إنه مخيم يعيش فيه سكان ونازحون وعائلات ضاقت بها أماكن النزوح، وفيه أطفال ومرضى وكبار سن يحاولون النجاة من حرب لا تترك مكانًا مستقرًا. لذلك كان حجم الضحايا صادمًا، وكانت آثار العملية أكبر من أي بيان عسكري يمكن أن يلخصها.\r\n\r\nفي المستشفيات القريبة، وصل المصابون بأعداد كبيرة، بعضهم على عربات، وبعضهم محمولون على الأكتاف، وبعضهم بلا مرافق يعرف اسمه. الطواقم الطبية واجهت ضغطًا هائلًا، بينما كان الأهالي يبحثون بين المصابين والشهداء عن أبنائهم وذويهم.\r\n\r\nهذا اليوم كشف مرة أخرى أن العمليات العسكرية في مناطق مكتظة تعني، قبل أي شيء، كارثة على المدنيين. فكل شارع في المخيم يحمل بيتًا، وكل بيت يحمل عائلة، وكل قصف يترك خلفه قصصًا لا يمكن اختصارها في أرقام.\r\n\r\nالنصيرات بقيت علامة موجعة في الحرب، لأنها أظهرت كيف يمكن للحظة واحدة أن تغيّر حياة آلاف الناس، وأن تحوّل مخيمًا كاملًا إلى ذاكرة مفتوحة من الفقد والدمار.', 'published', '2026-04-28 08:30:59', '2026-04-28 08:30:51', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:25:44', '2026-04-28 08:30:59', 'articles/covers/النصيرات.jpg'),
(37, 1, 8, 'المواصي: خيام النازحين تتحول إلى شاهد جديد على أن لا مكان آمنًا', 'al-mawasi-khan-younis-strike', 'في المواصي غرب خان يونس، حيث لجأت عائلات كثيرة إلى الخيام هربًا من القصف، جاء الاستهداف ليهدم ما تبقى من فكرة المكان الآمن. كان الناس هناك يعيشون حياة مؤقتة وقاسية، بين الرمل والخيام وشح المياه والطعام، لكنهم كانوا يعتقدون أن الابتعاد عن مراكز المدن قد يمنحهم فرصة أكبر للنجاة.\r\n\r\nفي لحظة واحدة، تبدلت الصورة. الخيام التي كانت تحاول ستر العائلات تحولت إلى بقايا ممزقة، وارتفع الدخان فوق منطقة مكتظة بالنازحين. أطفال ركضوا بلا وجهة، أمهات بحثن عن أبنائهن، ورجال حاولوا إسعاف المصابين بما توفر من وسائل بسيطة.\r\n\r\nما جعل مشهد المواصي قاسيًا هو أن الضحايا كانوا في منطقة لجأوا إليها أصلًا من الحرب. لم يكونوا يبحثون عن مواجهة، بل عن مساحة ينامون فيها بعيدًا عن القصف. لكن الحرب لحقت بهم إلى الخيمة، كما لحقت بغيرهم إلى المدرسة والمستشفى والمخيم.\r\n\r\nالصورة في المواصي كانت أقوى من أي شرح: خيمة محترقة، طفل يبكي، رجل يحمل مصابًا، ونازح ينظر حوله كأنه يسأل: إلى أين نذهب بعد الآن؟ هذا السؤال صار عنوانًا يوميًا في غزة، حيث لا توجد خريطة واضحة للأمان.\r\n\r\nاستهداف المواصي بقي حدثًا مفصليًا لأنه ضرب منطقة ارتبطت في وعي الناس بالنزوح والاحتماء، وأعاد تأكيد الحقيقة الأكثر قسوة في هذه الحرب: داخل غزة، قد يرحل الإنسان من مكان إلى آخر، لكنه لا يخرج من دائرة الخطر.', 'published', '2026-04-28 08:29:47', '2026-04-28 08:29:20', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:27:45', '2026-04-28 08:29:47', 'articles/covers/قصف خيام النازحين.webp'),
(38, 8, 9, 'الجيش الإسرائيلي يعلن السيطرة على محور فيلادلفيا ومعبر رفح يعمّق خنق غزة', 'israeli-army-philadelphi-corridor-rafah-crossing-control', 'في تطور عسكري وسياسي لافت، أعلن الجيش الإسرائيلي تحقيق سيطرة عملياتية على محور فيلادلفيا على الحدود بين قطاع غزة ومصر، في خطوة اعتبرتها إسرائيل جزءًا من عملياتها العسكرية في منطقة رفح. هذا الإعلان لم يكن مجرد تفصيل ميداني، بل محطة مهمة في مسار الحرب، لأنه يرتبط بأحد أكثر المواقع حساسية في جنوب قطاع غزة.\r\n\r\nمحور فيلادلفيا ومعبر رفح لا يمثلان حدودًا جغرافية فقط، بل يشكلان بالنسبة لسكان غزة منفذًا حيويًا ارتبط لسنوات بالحركة، والمساعدات، وسفر المرضى، وخروج الحالات الإنسانية. ومع تصاعد العمليات الإسرائيلية في رفح، أصبح هذا الشريط الحدودي عنوانًا جديدًا للصراع بين الحسابات العسكرية الإسرائيلية والكارثة الإنسانية التي يعيشها المدنيون.\r\n\r\nمن زاوية الشؤون الإسرائيلية، عكس الإعلان رغبة الجيش والحكومة في تقديم السيطرة على المنطقة كإنجاز أمني، واعتبارها جزءًا من محاولة تضييق الخناق على حركة حماس ومنع تهريب السلاح. لكن في المقابل، كان أثر هذا التطور على غزة مباشرًا وقاسيًا، لأن السيطرة العسكرية على محيط المعابر تعني عمليًا مزيدًا من التعقيد في دخول المساعدات وحركة المرضى والنازحين.\r\n\r\nفي الأيام التي تلت تصاعد العمليات في رفح، حذرت جهات أممية وإنسانية من تدهور خطير في تدفق المساعدات، ومن أن إغلاق المعابر الجنوبية يهدد العمليات الإنسانية ويزيد خطر المجاعة. بالنسبة للعائلات المحاصرة داخل القطاع، لم يكن الخبر مجرد إعلان عسكري إسرائيلي، بل إشارة إلى أن طريق النجاة أصبح أضيق، وأن الغذاء والدواء والوقود صاروا أبعد من أي وقت مضى.\r\n\r\nهذا الحدث يكشف كيف تتحول القرارات العسكرية الإسرائيلية إلى واقع يومي قاسٍ على المدنيين في غزة. فحين تتحدث إسرائيل عن السيطرة والعمليات الأمنية، يعيش الناس في المقابل نقص الطعام، وتعطل الإجلاء الطبي، واشتداد الحصار، والخوف من موجات نزوح جديدة.\r\n\r\nلذلك لا يمكن قراءة السيطرة على محور فيلادلفيا ومعبر رفح كحدث عسكري فقط، بل كجزء من معادلة أوسع في الحرب: أمن تقوله إسرائيل في بياناتها، وحصار يعيشه الفلسطينيون في تفاصيل حياتهم اليومية.', 'published', '2026-04-28 08:35:18', '2026-04-28 08:35:13', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:35:03', '2026-04-28 08:35:18', 'articles/covers/محور فلادلفيا.webp'),
(39, 9, 8, 'مؤسسة غزة الإنسانية: المساعدات الأمريكية التي تحوّلت إلى طريق موت في غزة', 'gaza-humanitarian-foundation-us-aid-death-trap', 'منذ بدء عمل ما يُعرف باسم \"مؤسسة غزة الإنسانية\" في قطاع غزة، لم يعد الحديث عن المساعدات الأمريكية مرتبطًا فقط بإدخال الطعام إلى المدنيين، بل أصبح مرتبطًا أيضًا بسؤال أكثر قسوة: كيف تحوّلت نقاط توزيع المساعدات إلى أماكن يخاف الناس الذهاب إليها، رغم أن الجوع يدفعهم نحوها كل يوم؟\r\n\r\nالمؤسسة التي قُدّمت باعتبارها آلية جديدة لتوزيع المساعدات داخل غزة، وُصفت من قبل خبراء أمميين بأنها أُنشئت بدعم أمريكي وإسرائيلي، في وقت كان فيه القطاع يعيش أزمة جوع خانقة وانهيارًا واسعًا في القدرة على إيصال الغذاء عبر الطرق الإنسانية التقليدية. وبالنسبة للمدنيين، لم تكن التفاصيل السياسية للمؤسسة هي الأهم، بل النتيجة اليومية: آلاف الجائعين يسيرون نحو نقاط التوزيع، ولا يعرفون إن كانوا سيعودون بالطعام أم لن يعودوا أصلًا.\r\n\r\nفي غزة، صار مشهد الذهاب إلى المساعدات مشهدًا مؤلمًا بحد ذاته. رجال وشبان وأحيانًا أطفال يخرجون من الخيام والبيوت المهدمة، يمشون لمسافات طويلة، وينتظرون وسط الزحام والخوف، فقط من أجل كيس طحين أو علبة غذاء. لكن الطريق إلى المساعدة، الذي كان يجب أن يكون طريق نجاة، تحوّل في مرات كثيرة إلى طريق موت.\r\n\r\nبحسب مكتب الأمم المتحدة لحقوق الإنسان، استمر مقتل فلسطينيين أثناء محاولتهم الوصول إلى الطعام، وقال المكتب إن المدنيين في غزة واجهوا خيارًا غير إنساني: إما الموت جوعًا أو المخاطرة بالقتل أثناء البحث عن الغذاء. وذكر أن الجيش الإسرائيلي أطلق النار وقصف فلسطينيين حاولوا الوصول إلى نقاط توزيع مرتبطة بمؤسسة غزة الإنسانية منذ بدء عملها في 27 مايو 2025. \r\n\r\nومع مرور الوقت، اتسعت الفاجعة. فقد قال مكتب الأمم المتحدة لحقوق الإنسان إن ما لا يقل عن 1,373 فلسطينيًا قُتلوا أثناء سعيهم للحصول على الطعام منذ 27 مايو، بينهم 859 في محيط مواقع مؤسسة غزة الإنسانية، و514 على طرق قوافل الغذاء التابعة للأمم المتحدة ومنظمات إنسانية أخرى. هذه الأرقام جعلت اسم المؤسسة حاضرًا في واحدة من أقسى صور الحرب: الجائع الذي يُقتل وهو يبحث عن الطعام. \r\n\r\nلم تعد \"مؤسسة غزة الإنسانية\" بالنسبة لكثيرين مجرد اسم لمؤسسة مساعدات، بل أصبحت رمزًا لنظام توزيع أثار غضبًا واتهامات واسعة. خبراء أمميون دعوا إلى تفكيك المؤسسة فورًا، وقالوا إن نموذجها مثّل مثالًا مقلقًا على استغلال الإغاثة الإنسانية لأهداف عسكرية وجيوسياسية، بدل أن تكون حماية للجائعين والنازحين. \r\n\r\nالمأساة هنا ليست فقط في عدد الشهداء، بل في طبيعة اللحظة التي سقطوا فيها. هؤلاء لم يذهبوا إلى ساحة قتال، بل إلى نقطة مساعدات. لم يحملوا سلاحًا، بل حملوا جوع عائلاتهم. كل واحد منهم كان خلفه بيت أو خيمة تنتظر شيئًا يؤكل، وأطفال يسألون متى يعود، وأم تخاف من خبر لا تريد سماعه.\r\n\r\nهذا الخبر يلخص واحدة من أكثر صور الحرب قسوة: أن تتحول المساعدة إلى مخاطرة، والطعام إلى امتحان نجاة، والجوع إلى طريق مفتوح على الموت. في غزة، لم يكن الناس بحاجة إلى مساعدات مشروطة بالخوف، بل إلى فتح آمن وكامل للمعابر، وإلى دخول الغذاء والدواء والوقود عبر منظومة إنسانية تحمي المدنيين بدل أن تدفعهم إلى مناطق الخطر.\r\n\r\nمؤسسة غزة الإنسانية ستبقى في ذاكرة الحرب عنوانًا مؤلمًا لمرحلة صار فيها المدني الفلسطيني يُقتل لا لأنه يقاتل، بل لأنه جائع ويحاول الوصول إلى الطعام.', 'published', '2026-04-28 08:52:10', '2026-04-28 08:40:36', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:40:24', '2026-04-28 08:52:10', 'articles/covers/GHI.webp'),
(40, 1, 8, 'نسف الكلية الجامعية للعلوم التطبيقية يمحو ذاكرة آلاف الطلبة في غزة', 'university-college-applied-sciences-gaza-destroyed', 'على مدار أيام العدوان الإسرائيلي المجرم بحق أهالي قطاع غزة والذي تواصل لنحو شهر من القصف والدمار والاستهداف، تعرضت الكلية الجامعية للعلوم التطبيقية في مقرها الرئيس بمدينة غزة إلى قصف واسع وغير مبرر من مدفعية الجيش الإسرائيلي والذي خلف دمارا واسعا في مبانيها وألحق أضرارا فادحة وخرابا كبيرا في مرافقها وقاعاتها الدراسية ومختبراتها العلمية وبنيتها التحتية، وذلك في محاولة من الاحتلال للنيل من عزيمة شعبنا ومؤسساته الأكاديمية والتعليمية.\r\n\r\nوتعتبر الكلية الجامعية للعلوم التطبيقية من أكبر مؤسسات التعليم العالي الفلسطينية التي تقدم خدمات التعليم المهني التطبيقي لأكثر من 9,000 طالب وطالبة من كافة شرائح المجتمع، إضافة إلى دورها الفاعل في دفع عجلة التنمية الاقتصادية للمجتمع الفلسطيني، حيث واجهت الحصار كباقي مؤسسات المجتمع الفلسطيني منذ عام 2007، ولم تتوقف عن تقديم خدماتها وبرامجها التعليمية انطلاقاً من رسالتها وقيمها.\r\n\r\nوفي حديثه قال الأستاذ الدكتور رفعت رستم رئيس الكلية: تلقينا نبأ استهداف مؤسستنا الغراء بالحزن والألم والاستهجان، حيث تهيأنا سابق وقبيل بدأ العدوان لاستقبال نحو 3,500 من الطلبة الجدد من خريجي الثانوية العامة لعام 2014، وافتتحنا مجموعة من الاختصاصات والبرامج المهنية الجديدة والمميزة التي تراعي حاجة سوق العمل المحلي وتلبي رغبات المجتمع الفلسطيني، كما قمنا بتجهيز المختبرات والمعامل التطبيقية لهذا الغرض.\r\n\r\nوأضاف رستم: في ظل هذه الأضرار الكبيرة والخسائر الضخمة التي لحقت بالبنية التحتية لكليتنا ومرافقها، فإننا سنواجه صعوبات كبيرة في البدء بالعام الدراسي الجديد وهذا سينعكس بشكل سلبي على قطاع التعليم المهني في قطاع غزة، وسيؤثر على العملية التعليمية في مختلف الجامعات والكليات التي ستستقبل الطلبة الجدد من خريجي الثانوية العامة.\r\n\r\nوأكد رستم أن هذه الأضرار التي لحقت بالكلية لن تضعف من عزيمة إدارتها وطاقمها الأكاديمي وطلبتها، بل ستزيدهم إيماناً وإصراراً على مواصلة العمل الدؤوب استمراراً للمسيرة التعليمية في أحلك الظروف وبأقل الموارد، معتبرا أن الدعم المعنوي الذي قدمته كل شعوب العالم في أيام العدوان ما هي إلا بداية لمراحل مختلفة من الدعم المعنوي والمادي لقطاع غزة كي تعود الحياة من جديد لكافة قطاعات المجتمع بشكل عام وقطاع التعليم بشكل خاص.\r\n\r\nمن جانبه أفاد السيد محمود حميد النائب الإداري أن الكلية تعرضت بشكل كبير إلى التدمير والتخريب، حيث استهدف القصف مباني الكلية ومرافقها وقاعاتها الدراسية ومختبراتها العلمية وورشها التطبيقية وبنيتها التحتية، إضافة إلى الأقسام الأكاديمية والأقسام الإدارية والوحدات المختلفة التي أتى الدمار عليها بالكامل وألحق فيها أضرارا كبيرة.\r\n\r\nوحول طبيعة الدمار الذي لحق في الكلية الجامعية أفاد حميد: لقد تم تدمير واحتراق محتويات مجموعة من الطوابق في مبنى الإدارة، وهي الطابق الخامس الذي يضم مكاتب رئاسة الأمناء ورئاسة الكلية والمساعدين والنواب، وكذلك الطابق الثالث الذي يشمل قسم المالية ومركز الحاسوب والطابق السابع الخاص بقسم التخطيط والعلاقات الخارجية، إلى جانب أضرار فادحة في قاعة المؤتمرات الكبرى في الكلية الجامعية على الطابق التاسع من مبنى الإدارة.\r\n\r\nوأضاف حميد: لحقت أضرارا واسعة في القاعات الدراسية في مبنى الطلاب ومبنى الطالبات، كما احترقت جميع محتويات مختبرات الحاسوب من أجهزة وشبكات وملحقات وأثاث، وتعرضت المصاعد الكهربائية وغرف الكهرباء والتحكم في المصاعد إلى أعطال فادحة، وأصيبت شبكات الكهرباء والحاسوب والمياه ووحدات التكييف بخراب كبير جراء القصف، وتعطلت مجموعة من مولدات الكهرباء ولحق بنظام توليد الكهرباء بالطاقة الشمسية أضرارا كبيرة وواسعة.\r\n\r\nوذكر أبو حميد أن معظم الواجهات الزجاجية للمباني وقواطع الألمونيوم وحوائط الجبس والسقوف المستعارة في المباني تعرضت للتدمير، إضافة إلى تضرر واحتراق عدد كبير من التجهيزات المكتبية والأثاث في القاعات والمكاتب الإدارية، مؤكدا أن واجهات المباني تشوهت بفعل القصف المباشر والاستهداف المبالغ فيه لمباني الكلية الجامعية الآمنة.', 'published', '2026-04-28 08:52:07', '2026-04-28 08:47:22', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:47:16', '2026-04-28 08:52:07', 'articles/covers/دمار الكلية.png'),
(41, 9, 8, 'استشهاد زميلنا المهندس باسل وسام أبو شمالة أثناء إعداده الطعام للنازحين والصائمين', 'martyrdom-engineer-basil-wissam-abu-shamala', 'في يوم عرفة، بتاريخ 5 يونيو 2025، ارتقى زميلنا المهندس باسل وسام أبو شمالة شهيدًا، بعدما تم استهدافه أثناء وجوده في مركبة \"جيب\" خلال عمله الإنساني في قطاع غزة. لم يكن ذاهبًا إلى مكان عسكري، ولم يكن يحمل سوى رسالة بسيطة وكبيرة في معناها: إعداد وجبات طعام للنازحين والصائمين وتوزيعها على من أنهكهم الجوع والحصار والنزوح.\r\n\r\nكان باسل واحدًا من أولئك الذين لم تسمح لهم الحرب أن يقفوا على الحياد أمام وجع الناس. في يوم يفترض أن تمتلئ فيه القلوب بالدعاء والرحمة، كان يذهب ليشارك في إعداد الطعام لمن فقدوا بيوتهم، وللعائلات التي تنتظر وجبة تسند أطفالها، وللصائمين الذين حوّل الحصار إفطارهم إلى أمنية صعبة.\r\n\r\nاستشهاده لا يختصر فقط فقدان شاب ومهندس وزميل عزيز، بل يكشف أيضًا قسوة الواقع في غزة، حيث صار العمل الإنساني نفسه محفوفًا بالخطر، وحيث يمكن لمن يخرج ليطعم الناس أن يعود خبرًا موجعًا بدل أن يعود حاملًا وجبات تنتظرها الخيام.\r\n\r\nفي غزة، لم تعد الحرب تلاحق الناس في بيوتهم فقط، بل في طريقهم إلى الماء، وفي انتظارهم للمساعدات، وفي محاولتهم إعداد الطعام، وفي كل فعل صغير يحاول أن يحفظ ما تبقى من الحياة. كان باسل في ذلك اليوم جزءًا من جهد إنساني بسيط في شكله، عظيم في أثره، لأن إطعام الجائع في زمن الحصار يصبح مقاومة للحرب والجوع معًا.\r\n\r\nرحل باسل وهو يؤدي عملًا يليق بأصحاب القلوب الحية؛ عمل لا تصنعه الشعارات، بل تصنعه الأيدي التي تعجن وتطبخ وتحمل الوجبات إلى النازحين. وبينما كانت العائلات تنتظر الطعام، جاء خبر استشهاده ليضيف وجعًا جديدًا إلى ذاكرة غزة، وليذكرنا أن كل شهيد في هذه الحرب ليس رقمًا، بل اسم وحياة وحلم ووجه يعرفه أهله وزملاؤه وأحبته.\r\n\r\nاستشهاد المهندس باسل وسام أبو شمالة سيبقى حاضرًا كقصة إنسان آمن بأن مساعدة الناس واجب، وأن الوقوف إلى جانب النازحين والجائعين لا يحتاج إلى منصب أو خطاب طويل، بل إلى قلب يتحرك حين يرى الألم. وفي يوم عرفة، حيث ترتفع الدعوات إلى السماء، ارتفع باسل شهيدًا وهو في طريقه لخدمة من يحتاجون إلى الرحمة والطعام والأمان.', 'published', '2026-04-28 08:52:34', '2026-04-28 08:52:29', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:51:09', '2026-04-28 08:52:34', 'articles/covers/باسل-ربنا يتقبله.jpg'),
(42, 1, 8, 'استشهاد الدكتور سعيد الزبدة مع عائلته يوجع التعليم في غزة', 'martyrdom-dr-said-al-zebda-ucas-president', 'في آخر أيام عام 2023، ارتقى الدكتور سعيد أنور الزبدة، رئيس الكلية الجامعية للعلوم التطبيقية في غزة، شهيدًا مع عدد من أفراد عائلته، بعد قصف استهدف حي الزيتون في مدينة غزة. لم يكن الخبر مجرد استشهاد أكاديمي فلسطيني بارز، بل كان ضربة موجعة لذاكرة التعليم في غزة، ولجيل كامل عرف الكلية الجامعية كمساحة للعلم والعمل والأمل.\r\n\r\nكان الدكتور سعيد الزبدة واحدًا من الوجوه الأكاديمية التي ارتبط اسمها بالتعليم التطبيقي والتقني في غزة. لم يكن حضوره داخل الكلية إداريًا فقط، بل كان جزءًا من مشروع تعليمي حاول أن يمنح الطلبة طريقًا نحو المستقبل، رغم الحصار وضيق الإمكانيات وتكرار الحروب.\r\n\r\nفي غزة، لا تبدو الجامعة مجرد مبنى. هي حلم طالب يريد أن يتخرج، ودفتر محاضرات، ومختبر، وممر يمشي فيه الشباب وهم يحاولون تخيل حياة مختلفة عن الحرب. لذلك، حين يُستهدف رئيس مؤسسة تعليمية، لا يكون الألم شخصيًا فقط، بل يمس معنى التعليم نفسه في مدينة تُحاصر وتُقصف وتُدفع نحو فقدان مستقبلها.\r\n\r\nاستشهاد الدكتور الزبدة مع عائلته جاء في سياق حرب لم تترك للمدنيين ولا للأكاديميين ولا للمؤسسات التعليمية مساحة آمنة. فالبيوت قُصفت، والجامعات دُمّرت، والطلبة تفرقوا بين النزوح والفقد، والأساتذة الذين كانوا يصنعون المعرفة صاروا هم أنفسهم أسماء في قوائم الشهداء.\r\n\r\nكان الدكتور سعيد الزبدة حاضرًا في مسيرة الكلية الجامعية للعلوم التطبيقية، وساهم في تطوير بيئة التعليم التقني والابتكار وريادة الأعمال. وبين القاعات والمختبرات وحاضنات المشاريع، كان هناك جهد طويل لبناء جيل يستطيع أن يعمل وينتج رغم واقع غزة القاسي.\r\n\r\nلكن الحرب جاءت لتقول إن استهداف غزة لا يطال الحجر وحده، بل يطال الإنسان الذي يعلّم، والطالب الذي يتعلم، والعائلة التي تنتظر، والمؤسسة التي تبني. ومع استشهاده، لم تخسر الكلية رئيسًا فقط، بل خسر التعليم في غزة أحد رموزه الذين آمنوا بأن المعرفة طريق نجاة وسط الحصار.\r\n\r\nرحل الدكتور سعيد الزبدة مع أفراد من عائلته، وبقي اسمه شاهدًا على واحدة من أقسى صور الحرب: أن يُقتل الأكاديمي في بيته، وأن تُفجع الجامعة برئيسها، وأن تتحول مسيرة التعليم إلى ذاكرة مثقلة بالفقد.\r\n\r\nهذا الخبر لا يحكي عن شخص واحد فقط، بل عن غزة التي يُستهدف فيها الطبيب والمهندس والأستاذ والطالب، وعن حرب لم تكتفِ بتدمير البيوت، بل امتدت إلى العقول والمؤسسات والأحلام التي كانت تحاول أن تبقى واقفة وسط الركام.', 'published', '2026-04-28 08:55:48', '2026-04-28 08:55:38', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 08:55:36', '2026-04-28 08:55:48', 'articles/covers/د.سعيد.webp'),
(43, 1, 9, 'استطلاع رأي: إسرائيل لم تنتصر في أي حرب منذ 7 أكتوبر', 'استطلاع-رأي-إسرائيل-لم-تنتصر-في-أي-حرب-منذ-7-أكتوبر', 'أظهر استطلاع رأي إسرائيلي، اليوم الثلاثاء، أن 57% من الإسرائيليين يعتقدون أن تل أبيب لم تنتصر في أي حرب منذ السابع من أكتوبر/تشرين الأول 2023.\r\n\r\n\r\nومنذ ذلك التاريخ، شنت إسرائيل حروبا على قطاع غزة ولبنان وإيران، وهجمات في اليمن وسوريا، وعمليات عسكرية في الضفة الغربية المحتلة.\r\n\r\nوقالت هيئة البث الإسرائيلية التي نشرت الاستطلاع إن معظم الإسرائيليين يرون أن الجيش الإسرائيلي لم يفز في أي ساحة حرب منذ أحداث السابع من أكتوبر، مضيفة أن 28% من المستطلعة آراؤهم يعتقدون أن إسرائيل انتصرت على الأقل في ساحة واحدة، في حين أجاب 15% بـ\"لا أعرف\".\r\n\r\n%28 من الإسرائيليين المستطلعة آراؤهم يعتقدون أن إسرائيل انتصرت على الأقل في ساحة حرب واحدة (الأوروبية)مخاوف إسرائيلية من تجدد طوفان الأقصى\r\n\r\nووفق الاستطلاع، يرى 73% من الإسرائيليين أن إبقاء حزب الله وحركة المقاومة الإسلامية (حماس) في وضعهما الحالي، دون تجريدهما من السلاح، يحمل نُذُر تجدد التهديدات ضد إسرائيل، وتكرار ما جرى في هجمات طوفان الأقصى.\r\n\r\nوشهد فجر 7 أكتوبر/تشرين الأول 2023 أكبر عملية للمقاومة الفلسطينية في قطاع غزة ضد إسرائيل، عُرفت باسم \"طوفان الأقصى\"، وشملت هجوما بريا وبحريا وجويا على القواعد العسكرية الإسرائيلية والمستوطنات المحاذية للقطاع.\r\n\r\nسياسيا، أظهر استطلاع رأي آخر تراجع حزب رئيس الوزراء الإسرائيلي بنيامين نتنياهو -الذي أمر بشن الحروب الثلاث على غزة ولبنان وإيران- إلى المركز الثاني، بعد تصدُّر تحالف جديد يحمل اسم \"معا\" اتجاهات التصويت.\r\n\r\nوأُجري الاستطلاع عقب إعلان رئيسَي الوزراء السابقين نفتالي بينيت ويائير لبيد اندماج حزبيهما في تحالف سياسي حمل اسم \"معا\".\r\n\r\nووفق نتائج الاستطلاع الذي تناول سيناريوهات متعددة لتوزيع المقاعد، فإن حزب \"معا\" سيحصل على 26 مقعدا في الكنيست، متجاوزا حزب الليكود بقيادة نتنياهو، الذي حل ثانيا بـ25 مقعدا، وهو الرصيد نفسه من المقاعد المسجل في الاستطلاع السابق.\r\n\r\nويضع هذا الاستطلاع رئيس الوزراء الإسرائيلي أمام معادلة انتخابية معقدة، فالليكود ما زال الحزب الأكبر بحسب هيئة البث الإسرائيلية، ونتنياهو ما زال يتقدم في استطلاعات الملاءمة لرئاسة الحكومة، لكنَّ معسكره لا يمتلك أغلبية مضمونة في الانتخابات المقبلة.', 'needs_revision', NULL, '2026-04-28 09:18:01', 0, 'author', NULL, NULL, NULL, NULL, NULL, '2026-04-28 09:17:59', '2026-04-28 09:18:08', 'articles/covers/بببب.webp');

