(1, 'معتز عزايزة', 'ma@gaza.ps', '$2y$12$JzAfbeKfj7x2XJpZOZN.0uTrhOdhZUeuZTqtAcNiRIQA1b1n2MHay', 'مصور صحفي فلسطيني من غزة، برز خلال الحرب من خلال توثيق المشاهد الإنسانية والميدانية بعدسته. يركز في عمله على نقل معاناة المدنيين وقصص الصمود اليومية، مع اهتمام خاص بإظهار الجانب الإنساني للحرب بعيدًا عن الأرقام المجردة.', 1, NULL, NULL, NULL, NULL, '2026-04-15 15:45:19', '2026-04-28 09:00:29', 'authors/profile-images/معتز عزايزه.jpg'),
(6, 'وائل الدحدوح', 'wd@gaza.ps', '$2y$12$Ft.S5lIJGcESN6gPSMslyuomqpQ0o0034C99FhuJveviTHyGqPQvC', 'صحفي فلسطيني مخضرم وواحد من أبرز الوجوه الإعلامية التي غطّت الحرب على غزة من الميدان. يمتلك خبرة طويلة في العمل الصحفي والتغطية المباشرة للأحداث السياسية والإنسانية، ويمتاز بأسلوبه الهادئ في نقل الوقائع وربطها بسياقها الإنساني والوطني.', 1, NULL, NULL, 1, NULL, '2026-04-18 14:12:32', '2026-04-28 09:00:21', 'authors/profile-images/وائل الدحدوح.jpg'),
(7, 'Claudia Lawson', 'tyxovumod@mailinator.com', '$2y$12$7W08prdRFsRHRl7.eyJrW.a/bBN1GRvliovhdvFtMhrJ141.ymmQm', 'Facilis adipisci qua', 1, NULL, NULL, 1, '2026-04-20 08:44:06', '2026-04-18 14:17:55', '2026-04-20 08:44:06', 'authors/profile-images/Default-Author-Photo.jpg'),
(8, 'هاني المصري', 'hm@gaza.ps', '$2y$12$oHZiWSWxbjwnd3LVIY9i0OoiCCaRO/H6Ie1xWq7f6hb7JUmB6H/Wm', 'كاتب ومحلل سياسي فلسطيني متخصص في الشأن الوطني الفلسطيني والتحولات الإقليمية المرتبطة بالقضية الفلسطينية. يمتلك خبرة طويلة في البحث السياسي وكتابة المقالات والدراسات، ويركز في تحليلاته على مسارات الحرب، الموقف الفلسطيني الداخلي، والخيارات السياسية المستقبلية.', 1, NULL, NULL, 1, NULL, '2026-04-28 07:31:28', '2026-04-28 09:00:14', 'authors/profile-images/هاني-المصري.jpg'),
(9, 'هند خضري', 'hkh@gaza.ps', '$2y$12$n2.g6h.XAN5qvtgwLK2ubuwQHL3me4Bz.ze0Y27.4peY0mVgaX.Ka', 'صحفية فلسطينية من غزة متخصصة في تغطية القضايا الإنسانية والاجتماعية والسياسية. برزت خلال الحرب من خلال نقل تفاصيل الحياة اليومية للمدنيين، وتسليط الضوء على آثار النزوح والحصار والقصف، مع اعتماد أسلوب صحفي مباشر وقريب من الواقع.', 1, NULL, NULL, 1, NULL, '2026-04-28 07:32:35', '2026-04-28 09:00:02', 'authors/profile-images/هند الخضري.webp');

